// NewNfcTagStub creates a server-side INfcTag wrapping the given
// server implementation. The returned value satisfies INfcTag
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewNfcTagStub(
	impl INfcTagServer,
) INfcTag {
	wrapper := &nfcTagStubWrapper{impl: impl}
	stub := &NfcTagStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
